INSERT INTO `v1_2776152fc36be4becd50cc7494ffd8a4b14b1f27459f327f0684b1f19f956423` VALUES (4, 1, 10011, "【加速】4以上：\nＴＰ上昇＋30\n重複可能の行動速度＋100％\n");
INSERT INTO `v1_2776152fc36be4becd50cc7494ffd8a4b14b1f27459f327f0684b1f19f956423` VALUES (9, 1, 10012, "【加速】9以上：\nユニオンバースト発動時に【烈風】＋１（最大99）\n20秒ごとに物理/魔法与ダメアップフィールド展\n開（【烈風】数×１％）\n");
INSERT INTO `v1_2776152fc36be4becd50cc7494ffd8a4b14b1f27459f327f0684b1f19f956423` VALUES (15, 1, 10013, "【加速】15以上：\n９秒ごとにＴＰ1000回復\n");
