INSERT INTO `v1_2776152fc36be4becd50cc7494ffd8a4b14b1f27459f327f0684b1f19f956423` VALUES (9, 2, 10022, "【弱体】9以上：\n敵への継続ダメージ＋2000％\n（最大30万ダメージ）\n");
