INSERT INTO `v1_2776152fc36be4becd50cc7494ffd8a4b14b1f27459f327f0684b1f19f956423` VALUES (15, 3, 10033, "【会心】15以上：\nクリティカルヒット時【看破】＋１（最大99）\n20秒ごとにランダムな敵１体に固定ダメージ×５回\n（毎回５万＋対象の【看破】数×５万ダメージ）\n");
INSERT INTO `v1_2776152fc36be4becd50cc7494ffd8a4b14b1f27459f327f0684b1f19f956423` VALUES (4, 4, 10041, "【強化】4以上：\nバトル開始20秒後、物理/魔法攻撃力アップフィー\nルド展開（現在値＋30％）\n敵へのダメージ減衰量緩和\n");
INSERT INTO `v1_2776152fc36be4becd50cc7494ffd8a4b14b1f27459f327f0684b1f19f956423` VALUES (9, 4, 10042, "【強化】9以上：\nさらにバトル開始40秒後、物理/魔法攻撃力アッ\nプフィールド展開（現在値＋50％）\nさらに敵へのダメージ減衰量緩和\n");
INSERT INTO `v1_2776152fc36be4becd50cc7494ffd8a4b14b1f27459f327f0684b1f19f956423` VALUES (15, 4, 10043, "【強化】15以上：\nさらにバトル開始60秒後、物理/魔法攻撃力アッ\nプフィールド展開（現在値＋70％）\nさらに敵へのダメージ減衰量緩和\n");
